    solutionCode: `import { ref, type Ref } from 'vue'

export function useToggle(initial = false): {
  value: Ref<boolean>
  toggle: () => void
  setTrue: () => void
  setFalse: () => void
} {
  const value = ref(initial)
  return {
    value,
    toggle: () => {
      value.value = !value.value
    },
    setTrue: () => {
      value.value = true
    },
    setFalse: () => {
      value.value = false
    },
  }
}
`,
