    solutionCode: `/** Solution sketch — NotesApp */
const selected = computed(
  () => notes.value.find((n) => n.id === selectedId.value) ?? null,
)

const visible = computed(() => {
  const q = query.value.trim().toLowerCase()
  if (!q) return notes.value
  return notes.value.filter((n) => n.title.toLowerCase().includes(q))
})

function addNote() {
  const title = draftTitle.value.trim()
  if (!title) return
  const note = { id: nextId++, title, body: draftBody.value }
  notes.value.push(note)
  selectedId.value = note.id
  draftTitle.value = ''
  draftBody.value = ''
}

function selectNote(id: number) {
  selectedId.value = id
}

function removeSelected() {
  if (selectedId.value == null) return
  notes.value = notes.value.filter((n) => n.id !== selectedId.value)
  selectedId.value = null
}
`,
